1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (count: number, wasAlive: boolean): boolean =>
12	  wasAlive ? count === 2 || count === 3 : count === 3;
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const alive = new Set(cells.map(cellKey));
16	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
17	
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const neighbor: Cell = [x + dx, y + dy];
21	      const k = cellKey(neighbor);
22	      const entry = neighborCounts.get(k);
23	      if (entry) entry.count++;
24	      else neighborCounts.set(k, { cell: neighbor, count: 1 });
25	    }
26	  }
27	
28	  const next: Cell[] = [];
29	  for (const [k, { cell, count }] of neighborCounts) {
30	    if (survives(count, alive.has(k))) next.push(cell);
31	  }
32	  return next;
33	}
34

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life — nextGeneration", () => {
5	  it("should return [] for empty input — empty grid stays empty", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	
9	  it("should kill a lone live cell — nextGeneration([[0,0]]) returns []", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	
13	  it("should kill two adjacent live cells (underpopulation) — nextGeneration([[0,1],[1,1]]) returns []", () => {
14	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
15	  });
16	
17	  it("should leave a 2x2 block unchanged (still life) — nextGeneration([[0,0],[1,0],[0,1],[1,1]]) returns the same four cells", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
19	    const sorted = [...result].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
20	    expect(sorted).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
21	  });
22	
23	  it("should birth the diagonal-completing cell from an L-shape (reproduction) — nextGeneration([[0,0],[1,0],[0,1]]) returns the 2x2 block [[0,0],[1,0],[0,1],[1,1]]", () => {
24	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
25	    const sorted = [...result].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
26	    expect(sorted).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
27	  });
28	
29	  it("should kill the center of a full 3x3 from overpopulation — center (1,1) is absent from nextGeneration of all nine cells of the 3x3", () => {
30	    const result = nextGeneration([
31	      [0, 0], [1, 0], [2, 0],
32	      [0, 1], [1, 1], [2, 1],
33	      [0, 2], [1, 2], [2, 2],
34	    ]);
35	    expect(result).not.toContainEqual([1, 1]);
36	  });
37	
38	  it("should oscillate a vertical blinker into a horizontal blinker — nextGeneration([[0,0],[0,1],[0,2]]) returns [[-1,1],[0,1],[1,1]]", () => {
39	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
40	    const sorted = [...result].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
41	    expect(sorted).toEqual([[-1, 1], [0, 1], [1, 1]]);
42	  });
43	});
